const express = require('express');
const app = express();
const PORT = process.env.PORT || 3000;

const HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>X-17 Technologies | WiFi Vending Machine Philippines</title>\n<meta name="description" content="X-17 Technologies — Premium WiFi Vending Machines (Piso WiFi). Plug and play, earn 24/7. Raspberry Pi powered. Shop now!">\n<link rel="preconnect" href="https://fonts.googleapis.com">\n<link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@400;600;700;900&family=Exo+2:wght@300;400;500;600;700&display=swap" rel="stylesheet">\n<style>\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\n:root{\n  --cyan:#00d4ff;\n  --cyan2:#00aacc;\n  --gold:#ffd700;\n  --gold2:#ffb300;\n  --blue-dark:#050d1a;\n  --blue-mid:#0a1628;\n  --blue-card:#0d1f3c;\n  --blue-border:#1a3a6b;\n  --text-main:#e8f4ff;\n  --text-muted:#7aa3cc;\n  --accent-green:#39ff14;\n  --radius:12px;\n}\nhtml{scroll-behavior:smooth}\nbody{\n  font-family:\'Exo 2\',sans-serif;\n  background:var(--blue-dark);\n  color:var(--text-main);\n  overflow-x:hidden;\n  line-height:1.6;\n}\n\n/* SCROLLBAR */\n::-webkit-scrollbar{width:6px}\n::-webkit-scrollbar-track{background:var(--blue-dark)}\n::-webkit-scrollbar-thumb{background:var(--cyan);border-radius:3px}\n\n/* SCROLL PROGRESS */\n#progress-bar{position:fixed;top:0;left:0;height:3px;background:linear-gradient(90deg,var(--cyan),var(--gold));width:0%;z-index:9999;transition:width 0.1s}\n\n/* PARTICLES */\n#particles{position:fixed;top:0;left:0;width:100%;height:100%;z-index:0;pointer-events:none;overflow:hidden}\n.particle{position:absolute;border-radius:50%;animation:float-up linear infinite;opacity:0}\n@keyframes float-up{0%{transform:translateY(100vh) scale(0);opacity:0}10%{opacity:0.6}90%{opacity:0.3}100%{transform:translateY(-10vh) scale(1);opacity:0}}\n\n/* NAVBAR */\nnav{\n  position:fixed;top:0;left:0;right:0;z-index:1000;\n  padding:0 5%;\n  height:70px;\n  display:flex;align-items:center;justify-content:space-between;\n  background:rgba(5,13,26,0);\n  backdrop-filter:blur(0px);\n  transition:all 0.4s ease;\n  border-bottom:1px solid transparent;\n}\nnav.scrolled{\n  background:rgba(5,13,26,0.95);\n  backdrop-filter:blur(20px);\n  border-bottom:1px solid rgba(0,212,255,0.2);\n}\n.nav-logo{\n  font-family:\'Orbitron\',monospace;\n  font-size:1.3rem;font-weight:900;\n  color:var(--cyan);\n  text-decoration:none;\n  letter-spacing:2px;\n  display:flex;align-items:center;gap:8px;\n}\n.nav-logo span{color:var(--gold)}\n.logo-icon{width:36px;height:36px;border:2px solid var(--cyan);border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:0.85rem;font-weight:900;color:var(--gold)}\n.nav-links{display:flex;gap:2rem;list-style:none}\n.nav-links a{color:var(--text-muted);text-decoration:none;font-size:0.88rem;font-weight:500;letter-spacing:1px;text-transform:uppercase;transition:color 0.3s;position:relative}\n.nav-links a::after{content:\'\';position:absolute;bottom:-4px;left:0;right:0;height:1px;background:var(--cyan);transform:scaleX(0);transition:transform 0.3s}\n.nav-links a:hover{color:var(--cyan)}\n.nav-links a:hover::after{transform:scaleX(1)}\n.nav-cta{\n  padding:0.5rem 1.4rem;\n  background:linear-gradient(135deg,var(--cyan),var(--cyan2));\n  color:#000;font-weight:700;font-size:0.85rem;\n  border:none;border-radius:6px;\n  cursor:pointer;text-decoration:none;\n  letter-spacing:1px;text-transform:uppercase;\n  transition:all 0.3s;\n}\n.nav-cta:hover{box-shadow:0 0 20px rgba(0,212,255,0.6);transform:translateY(-1px)}\n.hamburger{display:none;flex-direction:column;gap:5px;cursor:pointer;padding:4px}\n.hamburger span{width:24px;height:2px;background:var(--cyan);border-radius:2px;transition:all 0.3s}\n.mobile-menu{display:none;position:fixed;top:70px;left:0;right:0;background:rgba(5,13,26,0.98);backdrop-filter:blur(20px);border-bottom:1px solid rgba(0,212,255,0.2);padding:1.5rem;z-index:999}\n.mobile-menu.open{display:block}\n.mobile-menu a{display:block;padding:0.8rem 0;color:var(--text-main);text-decoration:none;font-size:1rem;border-bottom:1px solid rgba(255,255,255,0.05)}\n\n/* HERO */\n.hero{\n  position:relative;min-height:100vh;\n  display:flex;align-items:center;\n  padding:0 5%;\n  overflow:hidden;z-index:1;\n}\n.hero-bg{\n  position:absolute;inset:0;z-index:-1;\n  background:\n    radial-gradient(ellipse 80% 60% at 70% 50%, rgba(0,50,100,0.5) 0%, transparent 60%),\n    radial-gradient(ellipse 50% 50% at 20% 80%, rgba(0,212,255,0.08) 0%, transparent 50%),\n    var(--blue-dark);\n}\n.hero-grid{\n  position:absolute;inset:0;z-index:-1;\n  background-image:\n    linear-gradient(rgba(0,212,255,0.05) 1px,transparent 1px),\n    linear-gradient(90deg,rgba(0,212,255,0.05) 1px,transparent 1px);\n  background-size:60px 60px;\n  animation:grid-drift 20s linear infinite;\n}\n@keyframes grid-drift{0%{background-position:0 0}100%{background-position:60px 60px}}\n.hero-glow{position:absolute;top:20%;right:10%;width:500px;height:500px;background:radial-gradient(circle,rgba(0,212,255,0.12) 0%,transparent 70%);border-radius:50%;animation:pulse-glow 4s ease-in-out infinite;z-index:-1}\n@keyframes pulse-glow{0%,100%{transform:scale(1);opacity:0.6}50%{transform:scale(1.2);opacity:1}}\n.hero-content{max-width:580px;z-index:2;animation:fade-in-up 0.8s ease both}\n@keyframes fade-in-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n.hero-badge{\n  display:inline-flex;align-items:center;gap:8px;\n  background:rgba(0,212,255,0.1);\n  border:1px solid rgba(0,212,255,0.3);\n  border-radius:20px;padding:0.4rem 1rem;\n  font-size:0.78rem;font-weight:600;letter-spacing:2px;\n  color:var(--cyan);text-transform:uppercase;\n  margin-bottom:1.5rem;\n}\n.badge-dot{width:6px;height:6px;background:var(--cyan);border-radius:50%;animation:blink 1.5s ease-in-out infinite}\n@keyframes blink{0%,100%{opacity:1}50%{opacity:0.2}}\n.hero-title{\n  font-family:\'Orbitron\',monospace;\n  font-size:clamp(2rem,5vw,3.5rem);\n  font-weight:900;line-height:1.1;\n  margin-bottom:0.5rem;\n  color:#fff;\n}\n.hero-title .accent{\n  color:transparent;\n  -webkit-text-stroke:1px var(--cyan);\n  text-shadow:0 0 30px rgba(0,212,255,0.4);\n}\n.hero-title .gold{color:var(--gold)}\n.hero-sub{\n  font-size:clamp(1.1rem,2.5vw,1.5rem);\n  color:var(--cyan);font-weight:600;\n  letter-spacing:3px;text-transform:uppercase;\n  margin-bottom:1.5rem;\n}\n.hero-desc{color:var(--text-muted);font-size:1rem;line-height:1.7;margin-bottom:2rem;max-width:480px}\n.hero-stats{display:flex;gap:2rem;margin-bottom:2.5rem}\n.stat{text-align:center}\n.stat-num{font-family:\'Orbitron\',monospace;font-size:1.5rem;font-weight:700;color:var(--gold);display:block}\n.stat-label{font-size:0.72rem;color:var(--text-muted);letter-spacing:1px;text-transform:uppercase}\n.cta-group{display:flex;gap:1rem;flex-wrap:wrap}\n.btn-primary{\n  padding:0.9rem 2rem;\n  background:linear-gradient(135deg,var(--cyan),#0077aa);\n  color:#000;font-weight:700;font-size:0.95rem;\n  border:none;border-radius:8px;cursor:pointer;\n  text-decoration:none;letter-spacing:1px;\n  transition:all 0.3s;\n  display:inline-flex;align-items:center;gap:8px;\n  text-transform:uppercase;\n}\n.btn-primary:hover{box-shadow:0 0 30px rgba(0,212,255,0.7),0 0 60px rgba(0,212,255,0.3);transform:translateY(-2px);background:linear-gradient(135deg,#33e0ff,var(--cyan))}\n.btn-secondary{\n  padding:0.9rem 2rem;\n  background:transparent;\n  color:var(--text-main);font-weight:600;font-size:0.95rem;\n  border:1px solid rgba(0,212,255,0.4);border-radius:8px;\n  cursor:pointer;text-decoration:none;\n  letter-spacing:1px;text-transform:uppercase;\n  transition:all 0.3s;\n  display:inline-flex;align-items:center;gap:8px;\n}\n.btn-secondary:hover{border-color:var(--cyan);color:var(--cyan);background:rgba(0,212,255,0.05)}\n.hero-image{\n  position:absolute;right:0;top:50%;\n  transform:translateY(-50%);\n  width:45%;max-width:600px;\n  z-index:2;\n  animation:float-img 6s ease-in-out infinite;\n}\n@keyframes float-img{0%,100%{transform:translateY(calc(-50% - 10px))}50%{transform:translateY(calc(-50% + 10px))}}\n.hero-image img{width:100%;filter:drop-shadow(0 20px 60px rgba(0,212,255,0.4))}\n.hero-scroll{\n  position:absolute;bottom:40px;left:50%;transform:translateX(-50%);\n  display:flex;flex-direction:column;align-items:center;gap:8px;\n  color:var(--text-muted);font-size:0.72rem;letter-spacing:2px;text-transform:uppercase;\n  animation:fade-in-up 1s 0.5s both;\n}\n.scroll-line{width:1px;height:40px;background:linear-gradient(to bottom,var(--cyan),transparent);animation:scroll-pulse 2s ease-in-out infinite}\n@keyframes scroll-pulse{0%,100%{opacity:0.4}50%{opacity:1}}\n\n/* SECTION COMMON */\nsection{position:relative;z-index:1;padding:5rem 5%}\n.section-header{text-align:center;margin-bottom:4rem}\n.section-label{\n  font-size:0.72rem;font-weight:700;letter-spacing:4px;text-transform:uppercase;\n  color:var(--cyan);margin-bottom:0.8rem;display:block;\n}\n.section-title{\n  font-family:\'Orbitron\',monospace;\n  font-size:clamp(1.6rem,3.5vw,2.5rem);\n  font-weight:700;color:#fff;\n  line-height:1.2;\n}\n.section-title .accent{color:var(--cyan)}\n.section-title .gold{color:var(--gold)}\n.section-line{\n  width:60px;height:3px;\n  background:linear-gradient(90deg,var(--cyan),var(--gold));\n  margin:1rem auto 0;border-radius:2px;\n}\n\n/* TICKER */\n.ticker{\n  background:linear-gradient(90deg,var(--cyan),var(--gold),var(--cyan));\n  padding:0.7rem 0;overflow:hidden;\n  position:relative;z-index:2;\n}\n.ticker-inner{\n  display:flex;white-space:nowrap;\n  animation:ticker-scroll 30s linear infinite;\n}\n.ticker-item{\n  font-family:\'Orbitron\',monospace;\n  font-size:0.8rem;font-weight:700;\n  color:#000;letter-spacing:2px;\n  padding:0 2rem;text-transform:uppercase;\n}\n.ticker-sep{color:#333;padding:0 1rem}\n@keyframes ticker-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n\n/* ABOUT */\n.about{background:var(--blue-mid)}\n.about-grid{display:grid;grid-template-columns:1fr 1fr;gap:4rem;align-items:center}\n.about-image{position:relative}\n.about-image img{width:100%;border-radius:var(--radius);border:1px solid rgba(0,212,255,0.2)}\n.about-badge-float{\n  position:absolute;bottom:-20px;right:-20px;\n  background:var(--blue-card);\n  border:1px solid var(--cyan);\n  border-radius:var(--radius);\n  padding:1rem 1.5rem;\n  text-align:center;\n}\n.about-badge-num{font-family:\'Orbitron\',monospace;font-size:2rem;font-weight:900;color:var(--gold);display:block}\n.about-badge-text{font-size:0.72rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:1px}\n.about-content p{color:var(--text-muted);line-height:1.8;margin-bottom:1.5rem;font-size:0.98rem}\n.about-features{display:grid;grid-template-columns:1fr 1fr;gap:1rem;margin-top:2rem}\n.feature-chip{\n  background:rgba(0,212,255,0.05);\n  border:1px solid rgba(0,212,255,0.2);\n  border-radius:8px;padding:0.8rem 1rem;\n  display:flex;align-items:center;gap:0.7rem;\n  font-size:0.85rem;font-weight:500;\n}\n.feature-chip .icon{color:var(--cyan);font-size:1.1rem}\n\n/* PRODUCTS */\n.products{background:var(--blue-dark)}\n.products-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:1.5rem}\n.product-card{\n  background:var(--blue-card);\n  border:1px solid var(--blue-border);\n  border-radius:var(--radius);\n  overflow:hidden;\n  transition:all 0.4s ease;\n  cursor:pointer;position:relative;\n}\n.product-card::before{\n  content:\'\';position:absolute;inset:0;\n  background:linear-gradient(135deg,rgba(0,212,255,0.05),transparent);\n  opacity:0;transition:opacity 0.4s;\n  pointer-events:none;\n}\n.product-card:hover{\n  border-color:rgba(0,212,255,0.5);\n  transform:translateY(-6px);\n  box-shadow:0 20px 50px rgba(0,212,255,0.15);\n}\n.product-card:hover::before{opacity:1}\n.product-img{\n  width:100%;height:220px;object-fit:cover;\n  transition:transform 0.4s;\n}\n.product-card:hover .product-img{transform:scale(1.04)}\n.product-body{padding:1.2rem}\n.product-badge{\n  display:inline-block;\n  background:linear-gradient(135deg,var(--gold),var(--gold2));\n  color:#000;font-size:0.7rem;font-weight:700;\n  padding:0.2rem 0.7rem;border-radius:4px;\n  letter-spacing:1px;text-transform:uppercase;\n  margin-bottom:0.7rem;\n}\n.product-name{font-family:\'Orbitron\',monospace;font-size:0.95rem;font-weight:700;color:#fff;margin-bottom:0.4rem}\n.product-router{color:var(--cyan);font-size:0.82rem;margin-bottom:0.8rem;font-weight:500}\n.product-features{list-style:none;margin-bottom:1rem}\n.product-features li{\n  font-size:0.8rem;color:var(--text-muted);\n  padding:0.2rem 0;\n  padding-left:1.2rem;position:relative;\n}\n.product-features li::before{content:\'✓\';position:absolute;left:0;color:var(--accent-green);font-size:0.75rem}\n.price-row{display:flex;align-items:flex-end;gap:0.5rem;margin-bottom:1rem}\n.price-old{font-size:0.8rem;color:var(--text-muted);text-decoration:line-through}\n.price-new{font-family:\'Orbitron\',monospace;font-size:1.3rem;font-weight:700;color:var(--gold)}\n.price-save{background:rgba(255,0,0,0.2);border:1px solid rgba(255,80,80,0.3);color:#ff8080;font-size:0.7rem;font-weight:700;padding:0.2rem 0.5rem;border-radius:4px}\n.card-btn{\n  width:100%;padding:0.7rem;\n  background:linear-gradient(135deg,rgba(0,212,255,0.15),rgba(0,212,255,0.05));\n  border:1px solid rgba(0,212,255,0.3);\n  color:var(--cyan);font-weight:700;font-size:0.85rem;\n  border-radius:6px;cursor:pointer;\n  text-align:center;letter-spacing:1px;\n  text-decoration:none;display:block;\n  transition:all 0.3s;text-transform:uppercase;\n}\n.card-btn:hover{background:linear-gradient(135deg,rgba(0,212,255,0.3),rgba(0,212,255,0.1));box-shadow:0 0 20px rgba(0,212,255,0.2)}\n\n/* HOW IT WORKS */\n.how-it-works{background:var(--blue-mid)}\n.hiw-grid{display:grid;grid-template-columns:1fr 1fr;gap:4rem;align-items:center}\n.hiw-img{border-radius:var(--radius);overflow:hidden;border:1px solid rgba(0,212,255,0.2)}\n.hiw-img img{width:100%;display:block}\n.steps{display:flex;flex-direction:column;gap:1.5rem}\n.step{\n  display:flex;gap:1rem;\n  background:var(--blue-card);\n  border:1px solid var(--blue-border);\n  border-radius:var(--radius);\n  padding:1.2rem;\n  transition:all 0.3s;position:relative;overflow:hidden;\n}\n.step::after{\n  content:\'\';position:absolute;left:0;top:0;bottom:0;width:3px;\n  background:var(--cyan);transform:scaleY(0);transition:transform 0.3s;\n}\n.step:hover{border-color:rgba(0,212,255,0.3);transform:translateX(6px)}\n.step:hover::after{transform:scaleY(1)}\n.step-num{\n  font-family:\'Orbitron\',monospace;\n  font-size:1.5rem;font-weight:900;\n  color:var(--cyan);opacity:0.4;\n  flex-shrink:0;width:40px;\n  line-height:1;\n}\n.step-content h4{font-size:0.95rem;font-weight:600;color:#fff;margin-bottom:0.3rem}\n.step-content p{font-size:0.82rem;color:var(--text-muted)}\n\n/* SPECS */\n.specs{background:var(--blue-dark)}\n.specs-grid{display:grid;grid-template-columns:1fr 1fr;gap:4rem;align-items:start}\n.specs-img img{width:100%;border-radius:var(--radius);border:1px solid rgba(0,212,255,0.2)}\n.spec-categories{display:flex;flex-direction:column;gap:1.2rem}\n.spec-cat{\n  background:var(--blue-card);\n  border:1px solid var(--blue-border);\n  border-radius:var(--radius);padding:1.2rem;\n}\n.spec-cat-title{\n  font-size:0.8rem;font-weight:700;color:var(--cyan);\n  text-transform:uppercase;letter-spacing:2px;\n  margin-bottom:0.8rem;\n  display:flex;align-items:center;gap:0.5rem;\n}\n.spec-cat-title::before{content:\'\';display:block;width:8px;height:8px;background:var(--cyan);border-radius:50%}\n.spec-items{display:grid;grid-template-columns:1fr 1fr;gap:0.5rem}\n.spec-item{font-size:0.82rem;color:var(--text-muted);padding-left:1rem;position:relative}\n.spec-item::before{content:\'›\';position:absolute;left:0;color:var(--gold)}\n\n/* WHY US */\n.why-us{background:var(--blue-mid)}\n.why-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:1.5rem}\n.why-card{\n  background:var(--blue-card);\n  border:1px solid var(--blue-border);\n  border-radius:var(--radius);\n  padding:2rem 1.5rem;\n  text-align:center;\n  transition:all 0.4s;\n  position:relative;overflow:hidden;\n}\n.why-card::before{\n  content:\'\';position:absolute;\n  top:-60px;left:50%;transform:translateX(-50%);\n  width:120px;height:120px;\n  background:radial-gradient(circle,rgba(0,212,255,0.1) 0%,transparent 70%);\n  transition:all 0.4s;\n}\n.why-card:hover{transform:translateY(-6px);border-color:rgba(0,212,255,0.4);box-shadow:0 20px 40px rgba(0,0,0,0.3)}\n.why-card:hover::before{top:-20px;background:radial-gradient(circle,rgba(0,212,255,0.2) 0%,transparent 70%)}\n.why-icon{\n  width:64px;height:64px;\n  background:linear-gradient(135deg,rgba(0,212,255,0.15),rgba(0,212,255,0.05));\n  border:1px solid rgba(0,212,255,0.3);\n  border-radius:16px;\n  margin:0 auto 1.2rem;\n  display:flex;align-items:center;justify-content:center;\n  font-size:1.8rem;\n}\n.why-title{font-family:\'Orbitron\',monospace;font-size:0.9rem;font-weight:700;color:#fff;margin-bottom:0.5rem}\n.why-desc{font-size:0.82rem;color:var(--text-muted);line-height:1.6}\n\n/* GALLERY */\n.gallery{background:var(--blue-dark)}\n.gallery-grid{\n  display:grid;\n  grid-template-columns:repeat(3,1fr);\n  gap:1rem;\n}\n.gallery-item{\n  position:relative;overflow:hidden;\n  border-radius:var(--radius);\n  border:1px solid var(--blue-border);\n  cursor:pointer;\n  aspect-ratio:4/3;\n}\n.gallery-item img{\n  width:100%;height:100%;object-fit:cover;\n  transition:transform 0.5s ease;\n}\n.gallery-item:hover img{transform:scale(1.08)}\n.gallery-overlay{\n  position:absolute;inset:0;\n  background:linear-gradient(to top,rgba(5,13,26,0.9) 0%,transparent 60%);\n  opacity:0;transition:opacity 0.3s;\n  display:flex;align-items:flex-end;\n  padding:1rem;\n}\n.gallery-item:hover .gallery-overlay{opacity:1}\n.gallery-label{font-size:0.82rem;font-weight:600;color:var(--cyan);letter-spacing:1px}\n.gallery-item.tall{grid-row:span 2}\n\n/* LIGHTBOX */\n.lightbox{\n  position:fixed;inset:0;background:rgba(0,0,0,0.95);\n  z-index:9999;display:none;\n  align-items:center;justify-content:center;\n  padding:2rem;\n}\n.lightbox.open{display:flex}\n.lightbox img{max-width:90%;max-height:90vh;border-radius:var(--radius);border:1px solid rgba(0,212,255,0.3)}\n.lightbox-close{\n  position:absolute;top:1.5rem;right:1.5rem;\n  width:44px;height:44px;background:rgba(255,255,255,0.1);\n  border:1px solid rgba(255,255,255,0.2);border-radius:50%;\n  color:#fff;font-size:1.3rem;cursor:pointer;\n  display:flex;align-items:center;justify-content:center;\n  transition:all 0.3s;\n}\n.lightbox-close:hover{background:rgba(0,212,255,0.3)}\n\n/* TESTIMONIALS */\n.testimonials{background:var(--blue-mid)}\n.testi-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:1.5rem}\n.testi-card{\n  background:var(--blue-card);\n  border:1px solid var(--blue-border);\n  border-radius:var(--radius);\n  padding:1.5rem;\n  position:relative;\n}\n.testi-card::before{\n  content:\'"\';\n  position:absolute;top:-10px;left:1.5rem;\n  font-size:5rem;color:rgba(0,212,255,0.1);\n  font-family:serif;line-height:1;\n}\n.stars{color:var(--gold);font-size:0.9rem;margin-bottom:1rem}\n.testi-text{color:var(--text-muted);font-size:0.88rem;line-height:1.7;margin-bottom:1.2rem;font-style:italic}\n.testi-author{display:flex;align-items:center;gap:0.8rem}\n.testi-avatar{\n  width:40px;height:40px;border-radius:50%;\n  background:linear-gradient(135deg,var(--cyan),var(--blue-card));\n  display:flex;align-items:center;justify-content:center;\n  font-family:\'Orbitron\',monospace;font-size:0.8rem;font-weight:700;color:var(--cyan);\n  border:1px solid rgba(0,212,255,0.3);flex-shrink:0;\n}\n.testi-name{font-size:0.88rem;font-weight:600;color:#fff}\n.testi-loc{font-size:0.75rem;color:var(--text-muted)}\n\n/* FAQ */\n.faq{background:var(--blue-dark)}\n.faq-list{max-width:800px;margin:0 auto;display:flex;flex-direction:column;gap:0.8rem}\n.faq-item{\n  background:var(--blue-card);\n  border:1px solid var(--blue-border);\n  border-radius:var(--radius);overflow:hidden;\n}\n.faq-q{\n  padding:1.2rem 1.5rem;\n  display:flex;justify-content:space-between;align-items:center;\n  cursor:pointer;font-weight:600;font-size:0.92rem;color:#fff;\n  transition:color 0.3s;\n  user-select:none;\n}\n.faq-q:hover{color:var(--cyan)}\n.faq-arrow{\n  width:24px;height:24px;border:1px solid rgba(0,212,255,0.3);border-radius:50%;\n  display:flex;align-items:center;justify-content:center;\n  flex-shrink:0;color:var(--cyan);font-size:0.8rem;\n  transition:transform 0.3s;\n}\n.faq-item.open .faq-arrow{transform:rotate(180deg)}\n.faq-a{\n  max-height:0;overflow:hidden;\n  padding:0 1.5rem;\n  color:var(--text-muted);font-size:0.88rem;line-height:1.7;\n  transition:all 0.3s ease;\n}\n.faq-item.open .faq-a{max-height:200px;padding:0 1.5rem 1.2rem}\n\n/* CONTACT */\n.contact{background:var(--blue-mid)}\n.contact-inner{\n  max-width:700px;margin:0 auto;text-align:center;\n}\n.contact-subtitle{color:var(--text-muted);font-size:1rem;line-height:1.7;margin-bottom:2.5rem}\n.contact-cards{display:flex;gap:1rem;justify-content:center;flex-wrap:wrap;margin-bottom:2.5rem}\n.contact-card{\n  background:var(--blue-card);border:1px solid var(--blue-border);\n  border-radius:var(--radius);padding:1.2rem 1.5rem;\n  text-align:center;min-width:160px;\n}\n.contact-card-icon{font-size:1.5rem;margin-bottom:0.5rem}\n.contact-card-label{font-size:0.72rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:1px;margin-bottom:0.3rem}\n.contact-card-val{font-size:0.88rem;font-weight:600;color:var(--cyan)}\n.btn-messenger{\n  display:inline-flex;align-items:center;gap:0.8rem;\n  padding:1rem 2.5rem;\n  background:linear-gradient(135deg,#0099ff,#0055cc);\n  color:#fff;font-weight:700;font-size:1rem;\n  border:none;border-radius:8px;cursor:pointer;\n  text-decoration:none;letter-spacing:1px;text-transform:uppercase;\n  transition:all 0.3s;\n}\n.btn-messenger:hover{box-shadow:0 0 30px rgba(0,153,255,0.6);transform:translateY(-2px)}\n.social-links{display:flex;gap:1rem;justify-content:center;margin-top:2rem}\n.social-link{\n  width:44px;height:44px;\n  background:rgba(255,255,255,0.05);\n  border:1px solid rgba(255,255,255,0.1);\n  border-radius:8px;\n  display:flex;align-items:center;justify-content:center;\n  text-decoration:none;font-size:1.1rem;\n  transition:all 0.3s;\n}\n.social-link:hover{background:rgba(0,212,255,0.15);border-color:var(--cyan)}\n\n/* FOOTER */\nfooter{\n  background:#020810;\n  border-top:1px solid rgba(0,212,255,0.15);\n  padding:3rem 5% 2rem;\n}\n.footer-grid{display:grid;grid-template-columns:2fr 1fr 1fr;gap:3rem;margin-bottom:2rem}\n.footer-brand .nav-logo{margin-bottom:1rem}\n.footer-desc{color:var(--text-muted);font-size:0.85rem;line-height:1.7}\n.footer-heading{font-family:\'Orbitron\',monospace;font-size:0.8rem;font-weight:700;color:var(--cyan);letter-spacing:2px;text-transform:uppercase;margin-bottom:1rem}\n.footer-links{list-style:none;display:flex;flex-direction:column;gap:0.5rem}\n.footer-links a{color:var(--text-muted);text-decoration:none;font-size:0.85rem;transition:color 0.3s}\n.footer-links a:hover{color:var(--cyan)}\n.footer-bottom{\n  border-top:1px solid rgba(255,255,255,0.05);\n  padding-top:1.5rem;\n  display:flex;justify-content:space-between;align-items:center;\n  flex-wrap:wrap;gap:1rem;\n}\n.footer-copy{color:var(--text-muted);font-size:0.8rem}\n.footer-tag{font-family:\'Orbitron\',monospace;font-size:0.7rem;color:var(--cyan);letter-spacing:2px}\n\n/* FLOATING MESSENGER */\n.float-messenger{\n  position:fixed;bottom:30px;right:30px;z-index:900;\n  width:60px;height:60px;border-radius:50%;\n  background:linear-gradient(135deg,#0099ff,#006fe6);\n  display:flex;align-items:center;justify-content:center;\n  cursor:pointer;text-decoration:none;\n  box-shadow:0 8px 25px rgba(0,153,255,0.4);\n  animation:float-btn 3s ease-in-out infinite;\n  transition:all 0.3s;\n}\n.float-messenger:hover{transform:scale(1.1);box-shadow:0 12px 35px rgba(0,153,255,0.6)}\n@keyframes float-btn{0%,100%{transform:translateY(0)}50%{transform:translateY(-6px)}}\n.float-messenger svg{width:28px;height:28px;fill:#fff}\n.float-pulse{\n  position:absolute;inset:-4px;border-radius:50%;\n  border:2px solid rgba(0,153,255,0.5);\n  animation:ring-pulse 2s ease-out infinite;\n}\n@keyframes ring-pulse{0%{transform:scale(1);opacity:1}100%{transform:scale(1.5);opacity:0}}\n\n/* SCROLL REVEAL */\n.reveal{opacity:0;transform:translateY(30px);transition:all 0.7s ease}\n.reveal.visible{opacity:1;transform:translateY(0)}\n\n/* RESPONSIVE */\n@media(max-width:900px){\n  .hero-image{display:none}\n  .hero-content{max-width:100%}\n  .about-grid,.hiw-grid,.specs-grid{grid-template-columns:1fr}\n  .about-image{order:-1}\n  .footer-grid{grid-template-columns:1fr}\n  .nav-links,.nav-cta{display:none}\n  .hamburger{display:flex}\n  .gallery-grid{grid-template-columns:repeat(2,1fr)}\n  .gallery-item.tall{grid-row:auto}\n}\n@media(max-width:600px){\n  section{padding:3rem 4%}\n  .hero-stats{gap:1rem}\n  .gallery-grid{grid-template-columns:1fr 1fr}\n  .footer-bottom{flex-direction:column;text-align:center}\n}\n</style>\n</head>\n<body>\n\n<div id="progress-bar"></div>\n<div id="particles"></div>\n\n<!-- LIGHTBOX -->\n<div class="lightbox" id="lightbox" onclick="closeLightbox(event)">\n  <button class="lightbox-close" onclick="document.getElementById(\'lightbox\').classList.remove(\'open\')">✕</button>\n  <img id="lightbox-img" src="" alt="">\n</div>\n\n<!-- NAV -->\n<nav id="navbar">\n  <a href="#hero" class="nav-logo"><div class="logo-icon">X17</div>X-17<span>Tech</span></a>\n  <ul class="nav-links">\n    <li><a href="#about">About</a></li>\n    <li><a href="#products">Products</a></li>\n    <li><a href="#how-it-works">How It Works</a></li>\n    <li><a href="#specs">Specs</a></li>\n    <li><a href="#contact">Contact</a></li>\n  </ul>\n  <a href="https://web.facebook.com/X17Technologies/" target="_blank" class="nav-cta">Inquire Now</a>\n  <div class="hamburger" onclick="toggleMenu()" id="hamburger">\n    <span></span><span></span><span></span>\n  </div>\n</nav>\n\n<div class="mobile-menu" id="mobileMenu">\n  <a href="#about" onclick="toggleMenu()">About</a>\n  <a href="#products" onclick="toggleMenu()">Products</a>\n  <a href="#how-it-works" onclick="toggleMenu()">How It Works</a>\n  <a href="#specs" onclick="toggleMenu()">Specs</a>\n  <a href="#gallery" onclick="toggleMenu()">Gallery</a>\n  <a href="#contact" onclick="toggleMenu()">Contact</a>\n  <a href="https://web.facebook.com/X17Technologies/" target="_blank" style="color:var(--cyan);font-weight:700;margin-top:0.5rem">💬 Message Us on Facebook</a>\n</div>\n\n<!-- HERO -->\n<section class="hero" id="hero">\n  <div class="hero-bg"></div>\n  <div class="hero-grid"></div>\n  <div class="hero-glow"></div>\n  <div class="hero-content">\n    <div class="hero-badge"><span class="badge-dot"></span>Philippines #1 Piso WiFi Supplier</div>\n    <h1 class="hero-title">\n      <span class="gold">WiFi</span> Vending<br>\n      <span class="accent">Machine</span><br>\n      Business\n    </h1>\n    <p class="hero-sub">Earn 24/7 — No Monthly Fees</p>\n    <p class="hero-desc">Plug-and-play WiFi vending machines powered by Raspberry Pi. Insert coins, connect, and go. The smartest passive income you can own today.</p>\n    <div class="hero-stats">\n      <div class="stat"><span class="stat-num">24/7</span><span class="stat-label">Auto Operation</span></div>\n      <div class="stat"><span class="stat-num">0</span><span class="stat-label">Monthly Fees</span></div>\n      <div class="stat"><span class="stat-num">∞</span><span class="stat-label">Lifetime License</span></div>\n    </div>\n    <div class="cta-group">\n      <a href="https://web.facebook.com/X17Technologies/" target="_blank" class="btn-primary">\n        <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M12 0C5.374 0 0 5.373 0 12c0 5.302 3.438 9.8 8.207 11.387.599.111.793-.261.793-.577v-2.234c-3.338.726-4.033-1.416-4.033-1.416-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.107-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23A11.509 11.509 0 0112 5.803c1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.23.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222v3.293c0 .319.192.694.801.576C20.566 21.797 24 17.3 24 12c0-6.627-5.373-12-12-12z"/></svg>\n        Message Us Now\n      </a>\n      <a href="#products" class="btn-secondary">View Products ↓</a>\n    </div>\n  </div>\n  <div class="hero-image">\n    <img src="data:image/jpeg;base64," alt="X-17 WiFi Vending Machine">\n  </div>\n  <div class="hero-scroll">\n    <span>Scroll</span>\n    <div class="scroll-line"></div>\n  </div>\n</section>\n\n<!-- TICKER -->\n<div class="ticker">\n  <div class="ticker-inner">\n    <span class="ticker-item">WiFi Vending Machine</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">Piso WiFi</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">Raspberry Pi Series</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">Earn 24/7</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">No Monthly Fees</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">Lifetime License</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">X-17 Technologies</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">Plug and Play</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">All Coins Accepted</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">WiFi Vending Machine</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">Piso WiFi</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">Raspberry Pi Series</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">Earn 24/7</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">No Monthly Fees</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">Lifetime License</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">X-17 Technologies</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">Plug and Play</span><span class="ticker-sep">★</span>\n    <span class="ticker-item">All Coins Accepted</span><span class="ticker-sep">★</span>\n  </div>\n</div>\n\n<!-- ABOUT -->\n<section class="about" id="about">\n  <div class="about-grid reveal">\n    <div class="about-image">\n      <img src="data:image/jpeg;base64," alt="X-17 Technologies Products">\n      <div class="about-badge-float">\n        <span class="about-badge-num">100%</span>\n        <span class="about-badge-text">Metal Case</span>\n      </div>\n    </div>\n    <div class="about-content">\n      <div class="section-header" style="text-align:left;margin-bottom:2rem">\n        <span class="section-label">About Us</span>\n        <h2 class="section-title">Powering Passive <span class="accent">Income</span> in the Philippines</h2>\n        <div class="section-line" style="margin-left:0"></div>\n      </div>\n      <p>X-17 Technologies is a Philippine-based tech company specializing in WiFi vending machines and Piso WiFi solutions. We design, build, and sell premium coin-operated internet hotspot machines that help everyday Filipinos earn passive income.</p>\n      <p>Our machines run on Raspberry Pi 3B with WiFi5 Soft — stable, high-speed, and lifetime licensed. Built from 100% metal with anti-tamper locks and built-in cooling fans, they\'re engineered to run 24/7 with zero maintenance headaches.</p>\n      <div class="about-features">\n        <div class="feature-chip"><span class="icon">🛡️</span> Anti-Tamper Lock</div>\n        <div class="feature-chip"><span class="icon">🌡️</span> Built-In Cooling Fan</div>\n        <div class="feature-chip"><span class="icon">⚡</span> 12V Power Supply</div>\n        <div class="feature-chip"><span class="icon">🔧</span> Lifetime License</div>\n        <div class="feature-chip"><span class="icon">📡</span> Remote Monitoring</div>\n        <div class="feature-chip"><span class="icon">💰</span> All Coins Accepted</div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- PRODUCTS -->\n<section class="products" id="products">\n  <div class="section-header reveal">\n    <span class="section-label">Our Products</span>\n    <h2 class="section-title">WiFi Vending Machines — <span class="gold">Raspberry Pi Series</span></h2>\n    <div class="section-line"></div>\n  </div>\n  <div class="products-grid reveal">\n    <div class="product-card">\n      <img class="product-img" src="data:image/jpeg;base64," alt="With Mercusys MW301R" onclick="openLightbox(this.src)">\n      <div class="product-body">\n        <span class="product-badge">Best Value</span>\n        <div class="product-name">RPI Series + Mercusys</div>\n        <div class="product-router">With Mercusys MW301R Router</div>\n        <ul class="product-features">\n          <li>Raspberry Pi 3B 1G Motherboard</li>\n          <li>100% Metal Case + Waterproof Sticker</li>\n          <li>WiFi5 Soft — Lifetime License</li>\n          <li>All Coins Accepted (₱1, ₱5, ₱10, ₱20)</li>\n          <li>Full Admin + Remote Monitoring</li>\n        </ul>\n        <div class="price-row">\n          <span class="price-old">₱10,299</span>\n          <span class="price-new">₱8,799</span>\n          <span class="price-save">Save ₱1,500</span>\n        </div>\n        <a href="https://web.facebook.com/X17Technologies/" target="_blank" class="card-btn">Inquire Now →</a>\n      </div>\n    </div>\n    <div class="product-card">\n      <img class="product-img" src="data:image/jpeg;base64," alt="With Comfast EW73" onclick="openLightbox(this.src)">\n      <div class="product-body">\n        <span class="product-badge">Popular</span>\n        <div class="product-name">RPI Series + Comfast</div>\n        <div class="product-router">With Comfast EW73 Outdoor AP</div>\n        <ul class="product-features">\n          <li>Raspberry Pi 3B 1G Motherboard</li>\n          <li>100% Metal Case + Waterproof Sticker</li>\n          <li>WiFi5 Soft — Lifetime License</li>\n          <li>Up to 76 Users Simultaneously</li>\n          <li>Full Admin + Remote Monitoring</li>\n        </ul>\n        <div class="price-row">\n          <span class="price-old">₱11,679</span>\n          <span class="price-new">₱9,799</span>\n          <span class="price-save">Save ₱1,880</span>\n        </div>\n        <a href="https://web.facebook.com/X17Technologies/" target="_blank" class="card-btn">Inquire Now →</a>\n      </div>\n    </div>\n    <div class="product-card">\n      <img class="product-img" src="data:image/jpeg;base64," alt="With TP-Link EAP110" onclick="openLightbox(this.src)">\n      <div class="product-body">\n        <span class="product-badge">Best Seller</span>\n        <div class="product-name">RPI Series + TP-Link EAP110</div>\n        <div class="product-router">With TP-Link EAP110 Outdoor AP</div>\n        <ul class="product-features">\n          <li>Raspberry Pi 3B 1G Motherboard</li>\n          <li>100% Metal Case + Waterproof Sticker</li>\n          <li>WiFi5 Soft — Lifetime License</li>\n          <li>300Mbps Outdoor Access Point</li>\n          <li>Full Admin + Remote Monitoring</li>\n        </ul>\n        <div class="price-row">\n          <span class="price-old">₱11,999</span>\n          <span class="price-new">₱9,499</span>\n          <span class="price-save">Save ₱2,500</span>\n        </div>\n        <a href="https://web.facebook.com/X17Technologies/" target="_blank" class="card-btn">Inquire Now →</a>\n      </div>\n    </div>\n    <div class="product-card">\n      <img class="product-img" src="data:image/jpeg;base64," alt="With TP-Link EAP225" onclick="openLightbox(this.src)">\n      <div class="product-body">\n        <span class="product-badge" style="background:linear-gradient(135deg,#00d4ff,#0077aa);color:#000">Premium</span>\n        <div class="product-name">RPI Series + TP-Link EAP225</div>\n        <div class="product-router">With TP-Link EAP225 AC1200 Outdoor</div>\n        <ul class="product-features">\n          <li>Raspberry Pi 3B 1G Motherboard</li>\n          <li>100% Metal Case + Waterproof Sticker</li>\n          <li>WiFi5 Soft — Lifetime License</li>\n          <li>AC1200 MU-MIMO Gigabit</li>\n          <li>Indoor/Outdoor Coverage</li>\n        </ul>\n        <div class="price-row">\n          <span class="price-old">₱13,399</span>\n          <span class="price-new">₱11,399</span>\n          <span class="price-save">Save ₱2,000</span>\n        </div>\n        <a href="https://web.facebook.com/X17Technologies/" target="_blank" class="card-btn">Inquire Now →</a>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- HOW IT WORKS -->\n<section class="how-it-works" id="how-it-works">\n  <div class="section-header reveal">\n    <span class="section-label">Process</span>\n    <h2 class="section-title">How It <span class="accent">Works</span></h2>\n    <div class="section-line"></div>\n  </div>\n  <div class="hiw-grid reveal">\n    <div class="hiw-img">\n      <img src="data:image/jpeg;base64," alt="How Piso WiFi Works">\n    </div>\n    <div class="steps">\n      <div class="step">\n        <div class="step-num">01</div>\n        <div class="step-content">\n          <h4>Connect to WiFi</h4>\n          <p>Select the WiFi Vendo hotspot name on your phone or device from the available networks list.</p>\n        </div>\n      </div>\n      <div class="step">\n        <div class="step-num">02</div>\n        <div class="step-content">\n          <h4>Press "Insert Coin"</h4>\n          <p>All Philippine coins accepted — ₱1, ₱5, ₱10, and ₱20. Old and new designs both work.</p>\n        </div>\n      </div>\n      <div class="step">\n        <div class="step-num">03</div>\n        <div class="step-content">\n          <h4>Press "Done" on Your Phone</h4>\n          <p>After inserting your coin, tap the "Done" or "Connect" button on the portal page on your device.</p>\n        </div>\n      </div>\n      <div class="step">\n        <div class="step-num">04</div>\n        <div class="step-content">\n          <h4>Enjoy High-Speed Internet</h4>\n          <p>Automatic login — no password needed. Fast, stable connection ready to use instantly.</p>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- SPECS -->\n<section class="specs" id="specs">\n  <div class="section-header reveal">\n    <span class="section-label">Specifications</span>\n    <h2 class="section-title">Product <span class="gold">Specifications</span></h2>\n    <div class="section-line"></div>\n  </div>\n  <div class="specs-grid reveal">\n    <div class="specs-img">\n      <img src="data:image/jpeg;base64," alt="Product Specifications">\n    </div>\n    <div class="spec-categories">\n      <div class="spec-cat">\n        <div class="spec-cat-title">Hardware & Enclosure</div>\n        <div class="spec-items">\n          <div class="spec-item">Raspberry Pi 3B 1G</div>\n          <div class="spec-item">100% Metal Case</div>\n          <div class="spec-item">Waterproof Sticker</div>\n          <div class="spec-item">Custom Board</div>\n          <div class="spec-item">Built-In Cooling Fan</div>\n          <div class="spec-item">Anti-Tamper Lock</div>\n        </div>\n      </div>\n      <div class="spec-cat">\n        <div class="spec-cat-title">Software & Power</div>\n        <div class="spec-items">\n          <div class="spec-item">WiFi5 Soft OS</div>\n          <div class="spec-item">Lifetime License</div>\n          <div class="spec-item">12V, 5A Power Supply</div>\n          <div class="spec-item">USB to LAN Support</div>\n          <div class="spec-item">Fixed Random MAC</div>\n          <div class="spec-item">Custom Theme & Sound</div>\n        </div>\n      </div>\n      <div class="spec-cat">\n        <div class="spec-cat-title">Coin & Package Includes</div>\n        <div class="spec-items">\n          <div class="spec-item">Accepts ₱1, ₱5, ₱10, ₱20</div>\n          <div class="spec-item">Anti-Hooking Mechanism</div>\n          <div class="spec-item">Free LAN Cable 10m + 5m</div>\n          <div class="spec-item">Tarpaulin "How to Use"</div>\n          <div class="spec-item">1 Week Return Policy</div>\n          <div class="spec-item">1 Month Parts Warranty</div>\n        </div>\n      </div>\n      <div class="spec-cat">\n        <div class="spec-cat-title">Admin & Monitoring</div>\n        <div class="spec-items">\n          <div class="spec-item">Full Admin Access</div>\n          <div class="spec-item">Sales Monitoring</div>\n          <div class="spec-item">Remote Management</div>\n          <div class="spec-item">Speed & BW Control</div>\n          <div class="spec-item">After-Sales Support</div>\n          <div class="spec-item">Technical Assistance</div>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- WHY US -->\n<section class="why-us" id="why-us">\n  <div class="section-header reveal">\n    <span class="section-label">Why Choose Us</span>\n    <h2 class="section-title">Why <span class="accent">X-17 Technologies?</span></h2>\n    <div class="section-line"></div>\n  </div>\n  <div class="why-grid reveal">\n    <div class="why-card">\n      <div class="why-icon">🏭</div>\n      <div class="why-title">Premium Build</div>\n      <p class="why-desc">100% metal case with anti-tamper locks, cooling fan, and waterproof finish. Built for 24/7 outdoor and indoor deployment.</p>\n    </div>\n    <div class="why-card">\n      <div class="why-icon">💰</div>\n      <div class="why-title">Affordable Pricing</div>\n      <p class="why-desc">Starting at ₱8,799 with up to 20% savings. Lifetime license means no recurring software costs ever.</p>\n    </div>\n    <div class="why-card">\n      <div class="why-icon">⚡</div>\n      <div class="why-title">Plug & Play</div>\n      <p class="why-desc">No tech skills needed. Machine arrives ready to deploy — just plug in, connect to internet, and start earning.</p>\n    </div>\n    <div class="why-card">\n      <div class="why-icon">🌐</div>\n      <div class="why-title">Remote Monitoring</div>\n      <p class="why-desc">Manage your machines remotely. Monitor sales, control speed and bandwidth, edit time rates from anywhere.</p>\n    </div>\n    <div class="why-card">\n      <div class="why-icon">🎧</div>\n      <div class="why-title">After-Sales Support</div>\n      <p class="why-desc">1 week return policy, 1 month parts warranty, and dedicated technical support team that actually responds.</p>\n    </div>\n    <div class="why-card">\n      <div class="why-icon">🏆</div>\n      <div class="why-title">Proven & Trusted</div>\n      <p class="why-desc">Hundreds of satisfied operators across the Philippines. X-17 Technologies is the name that delivers.</p>\n    </div>\n  </div>\n</section>\n\n<!-- GALLERY -->\n<section class="gallery" id="gallery">\n  <div class="section-header reveal">\n    <span class="section-label">Gallery</span>\n    <h2 class="section-title">Product <span class="accent">Showcase</span></h2>\n    <div class="section-line"></div>\n  </div>\n  <div class="gallery-grid reveal">\n    <div class="gallery-item tall" onclick="openLightbox(\'data:image/jpeg;base64,\')">\n      <img src="data:image/jpeg;base64," alt="Actual Product">\n      <div class="gallery-overlay"><span class="gallery-label">Actual Product Photos</span></div>\n    </div>\n    <div class="gallery-item" onclick="openLightbox(\'data:image/jpeg;base64,\')">\n      <img src="data:image/jpeg;base64," alt="Side View">\n      <div class="gallery-overlay"><span class="gallery-label">Side View</span></div>\n    </div>\n    <div class="gallery-item" onclick="openLightbox(\'data:image/jpeg;base64,\')">\n      <img src="data:image/jpeg;base64," alt="Specifications">\n      <div class="gallery-overlay"><span class="gallery-label">Detailed Specs</span></div>\n    </div>\n    <div class="gallery-item" onclick="openLightbox(\'data:image/jpeg;base64,\')">\n      <img src="data:image/jpeg;base64," alt="Product Spec">\n      <div class="gallery-overlay"><span class="gallery-label">Full Specifications</span></div>\n    </div>\n    <div class="gallery-item" onclick="openLightbox(\'data:image/jpeg;base64,\')">\n      <img src="data:image/jpeg;base64," alt="TP-Link EAP225">\n      <div class="gallery-overlay"><span class="gallery-label">With TP-Link EAP225</span></div>\n    </div>\n  </div>\n</section>\n\n<!-- TESTIMONIALS -->\n<section class="testimonials" id="testimonials">\n  <div class="section-header reveal">\n    <span class="section-label">Reviews</span>\n    <h2 class="section-title">What Our <span class="accent">Customers Say</span></h2>\n    <div class="section-line"></div>\n  </div>\n  <div class="testi-grid reveal">\n    <div class="testi-card">\n      <div class="stars">★★★★★</div>\n      <p class="testi-text">Grabe yung kita ko sa unang buwan pa lang. Naka-recover na ko ng halos kalahati ng gastos. Ang ganda ng build quality, solid talaga yung metal case.</p>\n      <div class="testi-author">\n        <div class="testi-avatar">MR</div>\n        <div><div class="testi-name">Mark R.</div><div class="testi-loc">Cavite</div></div>\n      </div>\n    </div>\n    <div class="testi-card">\n      <div class="stars">★★★★★</div>\n      <p class="testi-text">Yung remote monitoring feature is a game changer. Tinitingnan ko na lang sa phone ko kung magkano na yung sales. No need pa pumunta sa machine.</p>\n      <div class="testi-author">\n        <div class="testi-avatar">JL</div>\n        <div><div class="testi-name">Jay L.</div><div class="testi-loc">Quezon City</div></div>\n      </div>\n    </div>\n    <div class="testi-card">\n      <div class="stars">★★★★★</div>\n      <p class="testi-text">X-17 tech support is very responsive. May tanong ako nung una about sa setup, sinagot agad. Yung machine is plug and play talaga, madaling i-setup.</p>\n      <div class="testi-author">\n        <div class="testi-avatar">AL</div>\n        <div><div class="testi-name">Ana L.</div><div class="testi-loc">Laguna</div></div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FAQ -->\n<section class="faq" id="faq">\n  <div class="section-header reveal">\n    <span class="section-label">FAQ</span>\n    <h2 class="section-title">Frequently Asked <span class="accent">Questions</span></h2>\n    <div class="section-line"></div>\n  </div>\n  <div class="faq-list reveal">\n    <div class="faq-item">\n      <div class="faq-q" onclick="toggleFaq(this)">\n        Kailangan ba ng technical knowledge para i-set up? <span class="faq-arrow">▾</span>\n      </div>\n      <div class="faq-a">Hindi. Plug and play ang lahat ng aming machines. Kasama sa package ang tarpaulin guide at mayroon kaming tech support para tulungan kayo sa setup.</div>\n    </div>\n    <div class="faq-item">\n      <div class="faq-q" onclick="toggleFaq(this)">\n        Anong internet connection ang kailangan? <span class="faq-arrow">▾</span>\n      </div>\n      <div class="faq-a">Kahit anong ISP — PLDT, Globe, Converge, Sky, or even LTE router. Kailangan lang ng existing internet connection na iko-connect sa machine via LAN cable (kasama sa package).</div>\n    </div>\n    <div class="faq-item">\n      <div class="faq-q" onclick="toggleFaq(this)">\n        Magkano ang average monthly income? <span class="faq-arrow">▾</span>\n      </div>\n      <div class="faq-a">Depende sa location at traffic. Sa mataong lugar tulad ng sari-sari store, palengke, o apartment area, madaling maabot ang ₱3,000–₱10,000+ per month. Mabilis ang ROI.</div>\n    </div>\n    <div class="faq-item">\n      <div class="faq-q" onclick="toggleFaq(this)">\n        May monthly fee ba ang software? <span class="faq-arrow">▾</span>\n      </div>\n      <div class="faq-a">Wala. Lifetime license ang kasama sa bawat machine. One-time bayad lang — walang recurring fees, walang subscriptions, walang hidden charges.</div>\n    </div>\n    <div class="faq-item">\n      <div class="faq-q" onclick="toggleFaq(this)">\n        Paano kung may defects ang machine? <span class="faq-arrow">▾</span>\n      </div>\n      <div class="faq-a">May 1 week return/refund policy (if defective) at 1 month warranty sa parts. May dedicated after-sales support din kami para sa technical assistance.</div>\n    </div>\n    <div class="faq-item">\n      <div class="faq-q" onclick="toggleFaq(this)">\n        Saan pwedeng i-order? Mayroon ba sa Lazada/Shopee? <span class="faq-arrow">▾</span>\n      </div>\n      <div class="faq-a">Yes! Available kami sa Lazada at Shopee under the store name X-17Technologies. Pwede rin mag-message directly sa aming Facebook page para sa personal inquiries at bulk orders.</div>\n    </div>\n  </div>\n</section>\n\n<!-- CONTACT -->\n<section class="contact" id="contact">\n  <div class="section-header reveal">\n    <span class="section-label">Get In Touch</span>\n    <h2 class="section-title">Ready to <span class="gold">Start Earning?</span></h2>\n    <div class="section-line"></div>\n  </div>\n  <div class="contact-inner reveal">\n    <p class="contact-subtitle">Message us on Facebook Messenger for pricing, bulk orders, or any questions. We respond fast.</p>\n    <div class="contact-cards">\n      <div class="contact-card">\n        <div class="contact-card-icon">📘</div>\n        <div class="contact-card-label">Facebook</div>\n        <div class="contact-card-val">X17Technologies</div>\n      </div>\n      <div class="contact-card">\n        <div class="contact-card-icon">🛒</div>\n        <div class="contact-card-label">Lazada / Shopee</div>\n        <div class="contact-card-val">X-17Technologies</div>\n      </div>\n      <div class="contact-card">\n        <div class="contact-card-icon">📍</div>\n        <div class="contact-card-label">Based In</div>\n        <div class="contact-card-val">Philippines</div>\n      </div>\n    </div>\n    <a href="https://web.facebook.com/X17Technologies/" target="_blank" class="btn-messenger">\n      <svg width="22" height="22" viewBox="0 0 24 24" fill="white"><path d="M12 0C5.374 0 0 5.373 0 12c0 5.302 3.438 9.8 8.207 11.387.599.111.793-.261.793-.577v-2.234c-3.338.726-4.033-1.416-4.033-1.416-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.107-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23A11.509 11.509 0 0112 5.803c1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.23.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222v3.293c0 .319.192.694.801.576C20.566 21.797 24 17.3 24 12c0-6.627-5.373-12-12-12z"/></svg>\n      Message Us on Facebook\n    </a>\n    <div class="social-links">\n      <a href="https://web.facebook.com/X17Technologies/" target="_blank" class="social-link" title="Facebook">📘</a>\n      <a href="https://web.facebook.com/X17Technologies/" target="_blank" class="social-link" title="Messenger">💬</a>\n      <a href="https://web.facebook.com/X17Technologies/" target="_blank" class="social-link" title="Shop">🛒</a>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer>\n  <div class="footer-grid">\n    <div class="footer-brand">\n      <a href="#hero" class="nav-logo" style="display:inline-flex;margin-bottom:1rem"><div class="logo-icon">X17</div>X-17<span>Technologies</span></a>\n      <p class="footer-desc">Premium WiFi Vending Machines and Piso WiFi solutions in the Philippines. Connect, Manage, and Earn.</p>\n    </div>\n    <div>\n      <div class="footer-heading">Quick Links</div>\n      <ul class="footer-links">\n        <li><a href="#about">About Us</a></li>\n        <li><a href="#products">Products</a></li>\n        <li><a href="#how-it-works">How It Works</a></li>\n        <li><a href="#specs">Specifications</a></li>\n        <li><a href="#gallery">Gallery</a></li>\n      </ul>\n    </div>\n    <div>\n      <div class="footer-heading">Connect</div>\n      <ul class="footer-links">\n        <li><a href="https://web.facebook.com/X17Technologies/" target="_blank">Facebook Page</a></li>\n        <li><a href="https://web.facebook.com/X17Technologies/" target="_blank">Messenger</a></li>\n        <li><a href="https://web.facebook.com/X17Technologies/" target="_blank">Lazada Store</a></li>\n        <li><a href="https://web.facebook.com/X17Technologies/" target="_blank">Shopee Store</a></li>\n        <li><a href="#faq">FAQ</a></li>\n      </ul>\n    </div>\n  </div>\n  <div class="footer-bottom">\n    <span class="footer-copy">© 2025 X-17 Technologies. All rights reserved. Philippines.</span>\n    <span class="footer-tag">CONNECT · MANAGE · EARN</span>\n  </div>\n</footer>\n\n<!-- FLOATING MESSENGER -->\n<a href="https://web.facebook.com/X17Technologies/" target="_blank" class="float-messenger" title="Message us on Facebook">\n  <div class="float-pulse"></div>\n  <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path d="M12 0C5.374 0 0 5.373 0 12c0 5.302 3.438 9.8 8.207 11.387.599.111.793-.261.793-.577v-2.234c-3.338.726-4.033-1.416-4.033-1.416-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.107-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23A11.509 11.509 0 0112 5.803c1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.23.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222v3.293c0 .319.192.694.801.576C20.566 21.797 24 17.3 24 12c0-6.627-5.373-12-12-12z"/></svg>\n</a>\n\n<script>\n// SCROLL PROGRESS\nconst bar = document.getElementById(\'progress-bar\');\nwindow.addEventListener(\'scroll\', () => {\n  const pct = (window.scrollY / (document.body.scrollHeight - window.innerHeight)) * 100;\n  bar.style.width = pct + \'%\';\n});\n\n// NAVBAR\nconst navbar = document.getElementById(\'navbar\');\nwindow.addEventListener(\'scroll\', () => {\n  navbar.classList.toggle(\'scrolled\', window.scrollY > 50);\n});\n\n// MOBILE MENU\nfunction toggleMenu() {\n  document.getElementById(\'mobileMenu\').classList.toggle(\'open\');\n}\n\n// PARTICLES\n(function() {\n  const container = document.getElementById(\'particles\');\n  const colors = [\'rgba(0,212,255,0.6)\', \'rgba(255,215,0,0.4)\', \'rgba(0,170,200,0.5)\'];\n  for (let i = 0; i < 40; i++) {\n    const p = document.createElement(\'div\');\n    p.className = \'particle\';\n    const size = Math.random() * 4 + 1;\n    p.style.cssText = `\n      width:${size}px;height:${size}px;\n      left:${Math.random()*100}%;\n      background:${colors[Math.floor(Math.random()*colors.length)]};\n      animation-duration:${Math.random()*15+10}s;\n      animation-delay:${Math.random()*10}s;\n    `;\n    container.appendChild(p);\n  }\n})();\n\n// SCROLL REVEAL\nconst observer = new IntersectionObserver((entries) => {\n  entries.forEach(e => {\n    if (e.isIntersecting) { e.target.classList.add(\'visible\'); observer.unobserve(e.target); }\n  });\n}, {threshold:0.1});\ndocument.querySelectorAll(\'.reveal\').forEach(el => observer.observe(el));\n\n// LIGHTBOX\nfunction openLightbox(src) {\n  document.getElementById(\'lightbox-img\').src = src;\n  document.getElementById(\'lightbox\').classList.add(\'open\');\n}\nfunction closeLightbox(e) {\n  if (e.target === document.getElementById(\'lightbox\')) {\n    document.getElementById(\'lightbox\').classList.remove(\'open\');\n  }\n}\ndocument.addEventListener(\'keydown\', e => {\n  if (e.key === \'Escape\') document.getElementById(\'lightbox\').classList.remove(\'open\');\n});\n\n// FAQ\nfunction toggleFaq(el) {\n  const item = el.parentElement;\n  item.classList.toggle(\'open\');\n}\n</script>\n</body>\n</html>';

